INSERT INTO public.questions VALUES ('0c0ad27e-debd-4cf7-870d-4764bb9f1d85', 'bd43b54e-b1b7-49da-929e-21171c504eaa', 'matching', ' Questions 14–20', NULL, '<p>Reading passage 2 has six paragraphs.</p>
<p>Choose the correct heading for each paragraph from the list of headings below.</p>
<p>Choose the correct number, <strong>i-ix</strong>. in the boxes 14-20.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "i Fluctuations in bittern numbers over time"}, {"optionText": "ii Research findings on habitat needs of adult bitterns"}, {"optionText": "iii Predators in the natural world"}, {"optionText": "iv The importance in the natural world"}, {"optionText": "v Initial habitat investigation and decisions"}, {"optionText": "vi The need for co-operation to ensure nature preservation"}, {"optionText": "vii Impressive results of initial intervention"}, {"optionText": "viii Determining how many bitterns there are"}], "matchingItems": null}', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">14. Đoạn 1 (Paragraph 1) — Đáp án: i (Fluctuations in bittern numbers over time)</strong></p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Vị trí thông tin:</strong> Xuyên suốt đoạn 1.</p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “By 1886… close to extinction. Fortunately, it recovered… in 1950… rose to a peak… By the 1980s… in trouble again… By 1997… imminent extinction”.</p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này liệt kê lịch sử thay đổi số lượng chim bittern theo thời gian: từ gần tuyệt chủng năm 1886, hồi phục vào 1950, rồi lại suy giảm vào những năm 1980 và 1997. Từ “Fluctuations” (sự biến động) mô tả chính xác quá trình tăng giảm này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">15. Đoạn 2 (Paragraph 2) — Đáp án: viii (Determining how many bitterns there are)</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Vị trí thông tin:</strong> Dòng 3-6 đoạn 2.</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Our first challenge was to develop standard methods to <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"67\">monitor their numbers</strong>… developed a method to <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"114\">count them</strong> using the sound patterns unique to each individual”.</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Nội dung chính của đoạn tập trung vào thách thức và phương pháp khoa học (sử dụng âm thanh) để đếm và xác định số lượng cá thể chim bittern hiện có.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">16. Đoạn 3 (Paragraph 3) — Đáp án: v (Initial habitat investigation and decisions)</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Vị trí thông tin:</strong> Dòng 1-2 và dòng 6 đoạn 3.</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Our first direct <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"29\">understanding</strong> of what breeding bitterns require… Based on this work, <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"100\">broad recommendations</strong>… were made, and funding was provided…”.</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này nói về việc bắt đầu tìm hiểu (investigation) nhu cầu môi trường sống và đưa ra các quyết định (decisions) như đưa ra khuyến nghị quản lý và cấp ngân quỹ để bảo tồn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">17. Đoạn 4 (Paragraph 4) — Đáp án: ii (Research findings on habitat needs of adult bitterns)</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Vị trí thông tin:</strong> Dòng 2-12 đoạn 4.</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “This showed clear <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"30\">preferences</strong> for feeding in the wetter reedbed areas… we located 87 bittern nests and found that female bitterns <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"144\">preferred</strong> to nest in…”.</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này trình bày các kết quả nghiên cứu cụ thể về sở thích môi trường sống của chim trưởng thành (cả con trống và con mái) trong việc kiếm ăn và làm tổ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">18. Đoạn 5 (Paragraph 5) — Đáp án: vii (Impressive results of initial intervention)</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Vị trí thông tin:</strong> Dòng 1-3 đoạn 5.</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"16\">success</strong> of the habitat prescriptions… has been <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"65\">spectacular</strong>. For instance… numbers gradually <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"112\">increased from one to ten</strong>…”.</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này nêu bật kết quả rực rỡ (spectacular/impressive) sau khi thực hiện các biện pháp can thiệp môi trường (intervention), minh chứng bằng việc số lượng chim tăng mạnh tại Minsmere.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">19. Đoạn 6 (Paragraph 6) — Đáp án: iv (The importance in the natural world)</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Vị trí thông tin:</strong> Dòng 5-13 đoạn 6.</p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…recommendations on habitat and water conditions to promote <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"74\">native fish populations</strong>… Young bitterns were found to seek out new sites… secure a more sustainable UK bittern population… less vulnerable to chance events…”.</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong data-path-to-node=\"13,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này nhấn mạnh tầm quan trọng của việc duy trì chuỗi thức ăn tự nhiên (cá bản địa) và tạo ra mạng lưới các khu vực cư trú mới để bảo vệ loài chim này trước các biến cố tự nhiên như mực nước biển dâng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">20. Đoạn 7 (Paragraph 7) — Đáp án: vi (The need for co-operation to ensure nature preservation)</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Vị trí thông tin:</strong> Dòng 5-11 đoạn 7.</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…success has only been achieved through the <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"58\">trust, hard work and dedication of all the managers, owners and wardens</strong> of sites that have implemented…”.</p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong data-path-to-node=\"15,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu kết luận của bài viết khẳng định rằng thành công không chỉ dựa vào khoa học mà cần sự hợp tác (co-operation) và tận tâm của tất cả những người liên quan (chủ đất, quản lý, người bảo vệ).</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('d3deea81-d535-4511-a7e6-f7715c4d7ea6', '7189ac80-695d-4054-a5a8-ad153dbc4138', 'fillup', 'Questions 34-37', '<p>Label the diagram below.</p>
<p>Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p><img src="data:image/png;base64," width="615" height="267" loading="lazy"></p>
<p>-network of {tunnels} helps to give the termites a constant<br>-{AIR} supply and to maintain a limited temperature range<br>-cellar to aid control of {moisture} levels in mound<br>-top of the mound permits {evaporation}</p>', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">34. Network of {tunnels} helps to give the termites a constant…</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"4,0,0\" data-index-in-node=\"20\">“The mound itself is formed of an <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"54\">intricate lattice of tunnels</strong>, which split into smaller and smaller tunnels…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc mô tả cấu trúc của gò mối như một mạng lưới tinh vi (intricate lattice) của các <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"100\">đường hầm (tunnels)</strong>. Mạng lưới này là “xương sống” để vận hành toàn bộ hệ thống bên trong.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">35. …gives a constant {air} supply and to maintain a limited temperature range</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"6,0,0\" data-index-in-node=\"20\">“This complex system of tunnels <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"52\">draws in air from the outside</strong>… ensuring them a <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"101\">continuous provision of fresh, breathable air</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Hệ thống đường hầm có chức năng hút không khí từ bên ngoài vào, cung cấp nguồn <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"91\">không khí (air)</strong> liên tục và tươi mới cho mối, đồng thời giúp điều hòa nhiệt độ không đổi (constant temperature).</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">36. Cellar to aid control of {moisture} levels in mound</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"8,0,0\" data-index-in-node=\"20\">“The mound also automatically <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"50\">regulates moisture</strong> in the air, by means of its <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"97\">underground ‘cellar’</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả chỉ ra rằng gò mối có một khu vực dưới lòng đất gọi là “tầng hầm” (cellar). Chức năng chính của bộ phận này là kiểm soát hoặc điều chỉnh mức độ <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"164\">độ ẩm (moisture)</strong> bên trong tổ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">37. Top of the mound permits {evaporation}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"10,0,0\" data-index-in-node=\"20\">“…and <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"28\">evaporation from the top of the mound</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Ngoài tầng hầm, việc điều chỉnh độ ẩm còn được thực hiện thông qua quá trình <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"89\">bay hơi (evaporation)</strong> diễn ra tại phần đỉnh (top) của gò mối.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('e48ce2a0-29d2-491c-aa78-ac5479c5ddfb', '7189ac80-695d-4054-a5a8-ad153dbc4138', 'radio', 'Questions 38-40', NULL, '<p><span style="font-family: arial, helvetica, sans-serif; font-size: 12pt;">Choose<strong> YES i</strong>f the statement agrees with the claims of the writer <strong>NO </strong>if the statement contradicts the claims of the writer <strong>NOT GIVEN </strong>if it is impossible to say what the writer thinks about this</span></p>', 'multiple_choice_single', '[{"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The termite mound appears to process its refuse material internally."}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Dr Soar’s reconstruction involves scanning a single photograph of a complete mound into acomputer."}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "New information about termite architecture could help people deal with future energy crises."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"1\"><strong data-path-to-node=\"1\" data-index-in-node=\"0\">38. The termite mound appears to process its refuse material internally.</strong></p>\n<ul data-path-to-node=\"2\">\n<li>\n<p data-path-to-node=\"2,0,0\"><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Đáp án: {YES}</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"2,1,0\"><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…none ever leaves the structure, indicating that there is also some kind of <strong data-path-to-node=\"2,1,0\" data-index-in-node=\"90\">internal waste-recycling system</strong>.” (Đoạn 4)</p>\n</li>\n<li>\n<p data-path-to-node=\"2,2,0\"><strong data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc xác nhận chất thải không bao giờ thoát ra ngoài tổ mà được xử lý bởi một hệ thống tái chế nội bộ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">39. Dr Soar’s reconstruction involves scanning a single photograph of a complete mound into a computer.</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án: {NO}</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…carves the plaster… into <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"42\">half-millimetre-thick slices</strong>, and <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"76\">photograph them sequentially</strong>.” (Đoạn 6)</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Phương pháp này không dùng một ảnh duy nhất mà chụp hàng loạt bức ảnh từ các lát cắt mỏng của tổ mối để dựng lại mô hình 3D.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">40. New information about termite architecture could help people deal with future energy crises.</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án: {YES}</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…there will <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"26\">not be enough fuel</strong> to drive air conditioners… findings will provide clues that aid the ultimate development of <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"139\">new kinds of human habitats</strong>.” (Đoạn 7)</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc học hỏi cách tổ mối tự làm mát giúp con người thiết kế nhà ở tiết kiệm năng lượng, đối phó với tình trạng thiếu hụt nhiên liệu trong tương lai.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('99c6e443-da82-49ae-a99f-a88e10cef0bd', '9e1776dd-ee65-4b43-a2d4-8cadedf709d7', 'radio', 'Questions 26', '', '<p>Choose the correct answer.</p>', 'multiple_choice', '[{"correct": 3, "options": [{"option_text": "how one species may be helped at the expense of another"}, {"option_text": "disagreement among environmentalists on methods to protect species from extinction"}, {"option_text": "fighting the destruction of wetland reedbeds"}, {"option_text": "how research and good management can save an endangered species "}], "question": "What is the main theme of Reading passage 2?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">26. What is the main theme of Reading passage 2?</strong></p>\n<ul data-path-to-node=\"11,0,1\">\n<li>\n<p data-path-to-node=\"11,0,1,0,0\"><strong data-path-to-node=\"11,0,1,0,0\" data-index-in-node=\"0\">Đáp án</strong>: how research and good management can save an endangered species</p>\n</li>\n<li>\n<p data-path-to-node=\"11,0,1,1,0\"><strong data-path-to-node=\"11,0,1,1,0\" data-index-in-node=\"0\">Giải thích</strong>: Xuyên suốt bài đọc, tác giả tập trung vào việc nghiên cứu khoa học (đoạn 2, 3, 4, 6) kết hợp với các biện pháp quản lý môi trường hiệu quả (đoạn 5, 7) đã giúp giải cứu thành công loài chim bittern khỏi nguy cơ tuyệt chủng. Điều này khớp với ý nghĩa của đáp án cuối cùng.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('0a11a391-0fcc-4622-8f45-0bd9a9923760', '9e0aeac0-4f2d-4f75-ad32-ff877189d86f', 'fillup', 'Questions 8–13', '<h3 data-section-id="1i6hwlk" data-start="999" data-end="1028">Complete the notes below.</h3>
<p data-start="1029" data-end="1069"><strong data-start="1029" data-end="1069">Write ONE WORD ONLY for each answer.</strong></p>
<h3 data-section-id="cbrkp1" data-start="1071" data-end="1108">The Cycle of Cranberry Production</h3>
<p data-start="1110" data-end="1120"><strong data-start="1110" data-end="1120">Winter</strong></p>
<ul data-start="1121" data-end="1294">
<li data-section-id="1hmw1tk" data-start="1121" data-end="1168">Growers {flood} the bogs to protect vines.</li>
<li data-section-id="lrh3e3" data-start="1169" data-end="1235">Sand is put on bogs to increase {drainage} and encourage growth.</li>
<li data-section-id="x1swfl" data-start="1236" data-end="1294">Trees are removed to promote the movement of {air}.</li>
</ul>
<p data-start="1296" data-end="1306"><strong data-start="1296" data-end="1306">Spring</strong></p>
<ul data-start="1307" data-end="1396">
<li data-section-id="1nqmfp1" data-start="1307" data-end="1357">{water} is supplied to protect against frost.</li>
<li data-section-id="1ss8529" data-start="1358" data-end="1396">{maintenance} is done to control pests.</li>
</ul>
<p data-start="1398" data-end="1408"><strong data-start="1398" data-end="1408">Summer</strong></p>
<ul data-start="1409" data-end="1447">
<li data-section-id="1y2ew4j" data-start="1409" data-end="1447">Growers check for {weed} growth.</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">8. flood — {Growers flood the bogs to protect vines.}</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"21,0,0\" data-index-in-node=\"26\">“In winter farmers often choose to flood the bogs, forming a protective layer that freezes and insulates the vines from extreme cold and drying winds.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Vào mùa đông, các nông dân thường chọn cách bơm nước làm ngập (<strong data-path-to-node=\"21,1,0\" data-index-in-node=\"75\">flood</strong>) các đầm lầy để tạo lớp bảo vệ cho các tổ dây leo. Từ cần điền là động từ phù hợp với chủ ngữ số nhiều <em data-path-to-node=\"21,1,0\" data-index-in-node=\"184\">Growers</em>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">9. drainage — {Sand is put on bogs to increase drainage and encourage growth.}</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong data-path-to-node=\"23,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"23,0,0\" data-index-in-node=\"26\">“On the frozen surface, sand is sometimes scattered so that, when thawed, the particles work into the bed and improve overall drainage, encouraging fresh shoots to establish.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong data-path-to-node=\"23,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ \"increase\" (tăng cường) trong câu hỏi đồng nghĩa với từ \"improve\" (cải thiện) trong bài đọc. Việc rải cát giúp cải thiện/tăng cường khả năng thoát nước (<strong data-path-to-node=\"23,1,0\" data-index-in-node=\"168\">drainage</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">10. air — {Trees are removed to promote the movement of air.}</strong></p>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong data-path-to-node=\"25,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"25,0,0\" data-index-in-node=\"26\">“To reduce disease risk and improve crop vigour, farmers also remove trees and scrub beside the bogs so that air can move through the site more freely...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"25,1,0\"><strong data-path-to-node=\"25,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ \"promote the movement of...\" (thúc đẩy sự chuyển động của...) đồng nghĩa với cụm \"...can move through the site more freely\" (có thể di chuyển tự do hơn qua khu vực). Thứ di chuyển ở đây chính là không khí (<strong data-path-to-node=\"25,1,0\" data-index-in-node=\"225\">air</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">11. water — {water is supplied to protect against frost.}</strong></p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong data-path-to-node=\"27,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"27,0,0\" data-index-in-node=\"26\">“With the coming of spring, the frozen cover is managed and water levels are adjusted; controlled water applications may be used at vulnerable times to shield budding shoots from sudden frosts.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong data-path-to-node=\"27,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Vào mùa xuân, từ \"supplied\" (cung cấp) tương ứng với cụm \"water applications\" (việc áp dụng/bơm nước). Nước (<strong data-path-to-node=\"27,1,0\" data-index-in-node=\"121\">water</strong>) được cấp vào nhằm bảo vệ chồi non khỏi sương giá đột ngột (<em data-path-to-node=\"27,1,0\" data-index-in-node=\"187\">shield budding shoots from sudden frosts</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">12. maintenance — {maintenance is done to control pests.}</strong></p>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong data-path-to-node=\"29,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"29,0,0\" data-index-in-node=\"26\">“During this phase growers perform routine maintenance on channels, pumps and irrigation lines and take steps to reduce pest pressure before the plants enter full growth.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong data-path-to-node=\"29,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Để kiểm tra và giảm áp lực sâu bệnh (<em data-path-to-node=\"29,1,0\" data-index-in-node=\"49\">reduce pest pressure / control pests</em>), những người trồng trọt tiến hành thực hiện việc bảo trì định kỳ (<strong data-path-to-node=\"29,1,0\" data-index-in-node=\"153\">maintenance</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">13. weed — {Growers check for weed growth.}</strong></p>\n<ul data-path-to-node=\"31\">\n<li>\n<p data-path-to-node=\"31,0,0\"><strong data-path-to-node=\"31,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"31,0,0\" data-index-in-node=\"26\">“Farmers inspect beds for any sign of weed emergence that would compete with the crop for nutrients and light, removing intruders promptly to protect potential yields.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"31,1,0\"><strong data-path-to-node=\"31,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Vào mùa hè, từ \"check for\" (kiểm tra) đồng nghĩa với động từ \"inspect\" (thanh tra, xem xét). Từ \"growth\" (sự phát triển) tương ứng với danh từ \"emergence\" (sự xuất hiện/nhô lên). Thứ mà người nông dân cần kiểm tra xem có mọc lên không là cỏ dại (<strong data-path-to-node=\"31,1,0\" data-index-in-node=\"258\">weed</strong>).</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('66318127-c9a4-4bf9-a0fb-9a1b8e2322af', '3f4efdec-3e06-49ff-9d6a-280318702b20', 'radio', 'Questions 27–31', '', '<p>Choose the correct letter, <strong data-start="48" data-end="64">A, B, C or D</strong>.</p>', 'multiple_choice', '[{"correct": 3, "options": [{"option_text": "A. They usually have hearing problems"}, {"option_text": "B. Some can play a musical instrument very well"}, {"option_text": "C. Some may be able to sing well-known melodies"}, {"option_text": "D. They have several inabilities in regard to music"}], "question": "What does the writer tell us about people with tone deafness (amusia) in the first paragraph?"}, {"correct": 1, "options": [{"option_text": "A. outlining some of the factors that cause amusia"}, {"option_text": "B. summarising some findings about people with amusia"}, {"option_text": "C. suggesting that people with amusia are disadvantaged"}, {"option_text": "D. comparing the singing ability of amusics with their sense"}], "question": "What is the writer doing in the second paragraph?"}, {"correct": 0, "options": [{"option_text": "A. People who are unable to speak can sometimes sing"}, {"option_text": "B. People with amusia usually have language problems too"}, {"option_text": "C. Speakers of tonal languages like Chinese rarely have amusia"}, {"option_text": "D. People with amusia have difficulty recognizing people by their voices"}], "question": "What does the writer say about the relationship between language ability and musical ability?"}, {"correct": 2, "options": [{"option_text": "A. learn how to sing in tune"}, {"option_text": "B. identify a song by its tune"}, {"option_text": "C. distinguish a sad tone from a happy tune"}, {"option_text": "D. recognise when a singer is not singing in tune"}], "question": "In the third paragraph, the writer notes that most amusics are able to"}, {"correct": 1, "options": [{"option_text": "A. claiming that amusics have problems in the auditory cortex"}, {"option_text": "B. outlining progress in understanding the brains of amusics"}, {"option_text": "C. proving that amusia is located in the temporal lobes"}, {"option_text": "D. explaining why studies of hearing are difficult"}], "question": "What is the writer doing in the fourth paragraph?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">27. D — They have several inabilities in regard to music.</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"4,0,0\" data-index-in-node=\"26\">“It is not simply that people with tone deafness (or ‘amusia’) are unable to sing in tune, they are also unable to discriminate between tones or recognize familiar melodies.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn 1 liệt kê một chuỗi các điểm yếu của người mắc chứng amusia: không thể hát đúng nhạc điệu (<em data-path-to-node=\"4,1,0\" data-index-in-node=\"108\">unable to sing in tune</em>), không thể phân biệt giữa các tông nhạc (<em data-path-to-node=\"4,1,0\" data-index-in-node=\"173\">unable to discriminate between tones</em>) và không nhận ra các giai điệu quen thuộc (<em data-path-to-node=\"4,1,0\" data-index-in-node=\"254\">recognize familiar melodies</em>). Cụm từ \"several inabilities\" (nhiều sự bất lực/không thể) khái quát hoàn hảo cho các thông tin này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">28. B — summarising some findings about people with amusia</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"6,0,0\" data-index-in-node=\"26\">“According to the research of Dr. Isabelle Peretz of the University of Montreal, amusia is more complicated than the inability to distinguish pitches.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong toàn bộ đoạn 2, tác giả liên tục liệt kê các kết quả từ nghiên cứu của Tiến sĩ Peretz: họ không phân biệt được quãng âm nhỏ hơn nửa cung, không nhận ra một nốt nhạc bị đổi lệch tông, và hát hoặc vỗ tay theo nhịp rất tệ. Việc tổng hợp các thông tin này chính là hành động tóm tắt lại các phát hiện khoa học (<strong data-path-to-node=\"6,1,0\" data-index-in-node=\"325\">summarising some findings</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">29. A — People who are unable to speak can sometimes sing.</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"8,0,0\" data-index-in-node=\"26\">“People with brain damage in areas critical to language are often still able to sing, despite being unable to communicate through speech.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Khi chứng minh năng lực ngôn ngữ và âm nhạc độc lập với nhau, tác giả đưa ra một thực tế: những người bị tổn thương vùng não ngôn ngữ dù không thể giao tiếp bằng lời nói (<em data-path-to-node=\"8,1,0\" data-index-in-node=\"183\">unable to communicate through speech / unable to speak</em>) nhưng họ thường vẫn có thể hát được (<strong data-path-to-node=\"8,1,0\" data-index-in-node=\"276\">still able to sing</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">30. C — distinguish a sad tone from a happy tune</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"10,0,0\" data-index-in-node=\"26\">“Amusics are also successful most of the time at detecting the mood of a melody, can identify a speaker based on his or her voice and can discriminate and identify environmental sounds.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn 3 khẳng định người mù nhạc phần lớn thời gian đều thành công trong việc nhận biết tâm trạng của một giai điệu (<em data-path-to-node=\"10,1,0\" data-index-in-node=\"128\">detecting the mood of a melody</em>). Việc phân biệt giữa một tông màu buồn và một giai điệu vui vẻ (<strong data-path-to-node=\"10,1,0\" data-index-in-node=\"224\">distinguish a sad tone from a happy tune</strong>) chính là biểu hiện cụ thể của khả năng nhận biết tâm trạng âm nhạc này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">31. B — outlining progress in understanding the brains of amusics</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"12,0,0\" data-index-in-node=\"26\">“New studies, however, have suggested that the deficits in amusia are located outside the auditory cortex.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn 4 phác họa lại hành trình nghiên cứu của giới khoa học qua từng giai đoạn: ban đầu họ nghi ngờ thùy thái dương (<em data-path-to-node=\"12,1,0\" data-index-in-node=\"129\">temporal lobes</em>), sau đó chuyển sang vùng vỏ não thính giác mới (<em data-path-to-node=\"12,1,0\" data-index-in-node=\"193\">temporal neocortex</em>), và cuối cùng các nghiên cứu mới phát hiện ra tổn khuyết thực chất nằm ngoài vỏ não thính giác. Sự sắp xếp thông tin này nhằm phác thảo tiến trình thấu hiểu cấu trúc não bộ của người mù nhạc (<strong data-path-to-node=\"12,1,0\" data-index-in-node=\"405\">outlining progress in understanding the brains</strong>).</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('a4949392-3ebd-4da4-a329-bd16029efb7c', '3f4efdec-3e06-49ff-9d6a-280318702b20', 'radio', 'Questions 32–35', '', '<p>Choose <strong data-start="1774" data-end="1781">YES</strong> – if the statement agrees with the views of the writer, <strong data-start="1839" data-end="1845">NO</strong> – if the statement contradicts the views of the writer, <strong data-start="1903" data-end="1916">NOT GIVEN</strong> – if it is impossible to say what the writer thinks about this</p>', 'yes_no_not_given', '[{"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Peretz’s research suggesting that amusia is a disorder is convincing"}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "People with musical ability are happier than those without this ability"}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "It is inappropriate to consider amusia as a real disorder"}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "People with amusia often have bad handwriting"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">32. NO</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"16,0,0\" data-index-in-node=\"26\">“Looking only at the research of Peretz in the field of neuropsychology of music, it would appear that amusia is some sort of disorder. As a student of neurobiology, however, I am skeptical.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói nghiên cứu của Peretz cho rằng amusia là một chứng rối loạn rất thuyết phục (<em data-path-to-node=\"16,1,0\" data-index-in-node=\"101\">convincing</em>). Ngược lại, tác giả khẳng định mình cảm thấy hoài nghi (<strong data-path-to-node=\"16,1,0\" data-index-in-node=\"169\">I am skeptical</strong>) về quan điểm đó. Vì quan điểm của tác giả mâu thuẫn trực tiếp với câu hỏi nên đáp án là <strong data-path-to-node=\"16,1,0\" data-index-in-node=\"273\">NO</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">33. NOT GIVEN</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"18,0,0\" data-index-in-node=\"26\">“Musical ability is culturally valued, and may have been a factor in survival at one point in human history, but it does not seem likely that it is being selected for on an evolutionary scale any longer.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nói năng lực âm nhạc mang giá trị văn hóa và từng đóng vai trò trong lịch sử tiến hóa, chứ <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"114\">hoàn toàn không có thông tin</strong> nào so sánh hoặc khẳng định người có năng khiếu âm nhạc thì sẽ sống hạnh phúc hơn (<em data-path-to-node=\"18,1,0\" data-index-in-node=\"226\">happier</em>) người không có.</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">34. YES</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"20,0,0\" data-index-in-node=\"26\">“Just because we recognize that basic musical ability is something that the vast majority of people have, this doesn’t mean that the lack of it is abnormal.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi cho rằng không thích hợp khi coi amusia là một chứng rối loạn thực sự (<em data-path-to-node=\"20,1,0\" data-index-in-node=\"91\">inappropriate to consider amusia as a real disorder</em>). Điều này đồng nhất với góc nhìn của tác giả khi khẳng định việc thiếu năng lực âm nhạc không có nghĩa là bất thường (<em data-path-to-node=\"20,1,0\" data-index-in-node=\"262\">not abnormal</em>), và việc quy chụp nó như một hội chứng rối loạn là đi quá xa (<em data-path-to-node=\"20,1,0\" data-index-in-node=\"338\">going too far</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">35. NOT GIVEN</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"22,0,0\" data-index-in-node=\"26\">“If no disadvantages can be found of having amusia, then it is no more a disability than having poor fashion sense or bad handwriting.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả đưa ra một phép so sánh giả định: nếu không tìm thấy tác hại nào của amusia thì nó cũng không hẳn là khuyết tật, giống như việc có gu thời trang kém hay có chữ viết tay xấu (<em data-path-to-node=\"22,1,0\" data-index-in-node=\"194\">bad handwriting</em>). Bài viết <strong data-path-to-node=\"22,1,0\" data-index-in-node=\"221\">không hề khẳng định</strong> một sự thật là người mù nhạc thì thường có chữ viết tay xấu ngoài đời thực.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('ae56b9fc-9ca0-40a1-be64-75382940c30d', '3f4efdec-3e06-49ff-9d6a-280318702b20', 'matching', 'Questions 36–40', '', '<p data-start="2288" data-end="2351">Complete each sentence with the correct ending, <strong data-start="2336" data-end="2343">A–H</strong>, below.</p>
<p data-start="2353" data-end="2428">Write the correct letter, <strong data-start="2379" data-end="2386">A–H</strong></p>', 'matching_sentence_endings', 'null', 'null', '{"layoutType": "standard", "summaryText": "", "answerOptions": [{"optionText": "an inability to hear when spoken language rises and falls"}, {"optionText": "considered to be desirable"}, {"optionText": "an inability to follow the beat of music"}, {"optionText": "not a problem"}, {"optionText": "not yet well understood"}, {"optionText": "a result of injury to the mother"}, {"optionText": "more marked than with other people"}, {"optionText": "associated with intelligence"}], "matchingItems": [{"questionPart": "The reason why some people are born with amusia is", "correctAnswer": "E"}, {"questionPart": "One of the difficulties amusics experience is", "correctAnswer": "C"}, {"questionPart": "For amusics, discrimination of meaning in speech is", "correctAnswer": "D"}, {"questionPart": "Certain reactions in the brain of an amusic are", "correctAnswer": "G"}, {"questionPart": "In most cultures, musical ability is", "correctAnswer": "B"}]}', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">36. E — The reason why some people are born with amusia is not yet well understood.</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"4,0,0\" data-index-in-node=\"26\">“...but recently research has been undertaken in an attempt to discover the cause of congenital amusia (when people are born with the condition)...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói về lý do tại sao một số người sinh ra đã mắc hội chứng amusia (<em data-path-to-node=\"4,1,0\" data-index-in-node=\"87\">born with amusia / congenital amusia</em>). Bài đọc viết rằng gần đây các nghiên cứu mới được thực hiện trong nỗ lực nhằm phát hiện ra nguyên nhân (<em data-path-to-node=\"4,1,0\" data-index-in-node=\"230\">in an attempt to discover the cause</em>). Điều này đồng nghĩa với việc nguyên nhân cốt lõi của nó hiện vẫn chưa được hiểu rõ (<strong data-path-to-node=\"4,1,0\" data-index-in-node=\"352\">not yet well understood</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">37. C — One of the difficulties amusics experience is an inability to follow the beat of music.</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"7,0,0\" data-index-in-node=\"26\">“As would be expected, amusics perform significantly worse at singing and tapping a rhythm along with a melody than do non-amusics.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Một trong những khó khăn mà người mù nhạc gặp phải (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"64\">difficulties amusics experience</em>) là họ thể hiện tệ hơn rất nhiều trong việc vỗ tay theo nhịp điệu của một giai điệu (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"181\">tapping a rhythm along with a melody</em>). Ý này tương đương với việc không thể theo kịp nhịp điệu, nhịp đập của âm nhạc (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"299\">an inability to follow the beat of music</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">38. D — For amusics, discrimination of meaning in speech is not a problem.</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"10,0,0\" data-index-in-node=\"26\">“Amusics who speak tonal languages, such as Chinese, do not report having any difficulty discriminating between words that differ only in their intonation.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đối với người mù nhạc, việc phân biệt ý nghĩa trong lời nói (<em data-path-to-node=\"10,1,0\" data-index-in-node=\"73\">discrimination of meaning in speech</em>) đối với các ngôn ngữ có thanh điệu là không gặp bất kỳ khó khăn nào (<em data-path-to-node=\"10,1,0\" data-index-in-node=\"179\">do not report having any difficulty</em>). Do đó, điều này hoàn toàn không phải là một trở ngại hay vấn đề đối với họ (<strong data-path-to-node=\"10,1,0\" data-index-in-node=\"293\">not a problem</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">39. G — Certain reactions in the brain of an amusic are more marked than with other people.</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"13,0,0\" data-index-in-node=\"26\">“When changes in tones are large, their brains overreact, showing twice as much activity on the right side of the brain as a normal brain hearing the same thing.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Một số phản ứng trong não của người mù nhạc khi nghe các tông nhạc lớn là hiện tượng não bộ phản ứng thái quá (<em data-path-to-node=\"13,1,0\" data-index-in-node=\"123\">overreact</em>), hoạt động mạnh gấp đôi so với não người bình thường nghe cùng một thứ. Phản ứng này biểu hiện rõ rệt, mạnh mẽ hơn nhiều so với người bình thường (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"281\">more marked than with other people</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">40. B — In most cultures, musical ability is considered to be desirable.</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"16,0,0\" data-index-in-node=\"26\">“Musical ability is culturally valued, and may have been a factor in survival at one point in human history...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong hầu hết các nền văn hóa, năng lực âm nhạc luôn được tôn trọng và đánh giá cao (<em data-path-to-node=\"16,1,0\" data-index-in-node=\"97\">culturally valued</em>). Vì thế, năng lực này được xem là một đặc điểm tốt, đáng ao ước và đáng hoan nghênh (<strong data-path-to-node=\"16,1,0\" data-index-in-node=\"201\">considered to be desirable</strong>).</p>\n</li>\n</ul>"}]', 2);
SET session_replication_role = DEFAULT;
